// ── Normalizer / Constitutional Gate ─────────────────────────────────────
// Every provider response passes through here.
// If it doesn't conform to the structural contract, it is rejected.
// Nothing enters the graph unchecked.

const ALLOWED_DOMAINS = [
  'physics', 'mathematics', 'biology',
  'cognition', 'systems', 'information'
];

const MIN_CONFIDENCE = 0.4;

// Extract text content from different provider response shapes
function extractText(item) {
  // Anthropic shape: item.content[0].text
  if (item.content && Array.isArray(item.content)) {
    return item.content.map(c => c.text || '').join('');
  }
  // OpenAI shape: item.choices[0].message.content
  if (item.choices && Array.isArray(item.choices)) {
    return item.choices[0]?.message?.content || '';
  }
  // LM Studio (same as OpenAI)
  if (item.choices) {
    return item.choices[0]?.message?.content || '';
  }
  // Direct string
  if (typeof item === 'string') return item;
  return '';
}

let raw;
try {
  const text = extractText(items[0].json);
  // Strip markdown fences if present
  const cleaned = text.replace(/```json|```/g, '').trim();
  raw = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Normalizer: provider returned non-JSON: ' + e.message);
}

// Validate concept
if (typeof raw.concept !== 'string' || raw.concept.trim() === '') {
  throw new Error('Normalizer: missing concept field');
}

// Validate domain
if (typeof raw.domain !== 'string' || !ALLOWED_DOMAINS.includes(raw.domain)) {
  throw new Error('Normalizer: invalid domain: ' + raw.domain);
}

// Validate confidence
if (typeof raw.confidence !== 'number') {
  raw.confidence = 0.5; // Default if missing
}
if (raw.confidence < MIN_CONFIDENCE) {
  throw new Error('Normalizer: confidence ' + raw.confidence + ' below threshold ' + MIN_CONFIDENCE);
}

// Reasoning fallback
if (typeof raw.reasoning !== 'string') {
  raw.reasoning = 'No reasoning provided.';
}

// Sanitize relations if present
const ALLOWED_RELATION_TYPES = ['supports', 'contradicts', 'extends', 'bridges'];
if (Array.isArray(raw.relations)) {
  raw.relations = raw.relations.filter(r =>
    r && typeof r.to !== 'undefined' && ALLOWED_RELATION_TYPES.includes(r.type)
  );
} else {
  raw.relations = [];
}

return [{ json: raw }];
